bool 
tlShaderColourParamChunk::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            param = (unsigned long) tlFourCC(new_val);
            return true;
        }
        case 1:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                value = tmp;
                return true;
            }
            return false;
        }
        default:
            return false;
    }
}

